/**
 * Deserializes an `ObjectNode` from a `JsonParser`.
 *
 * @param p the `JsonParser` to deserialize from
 * @param ctxt the `DeserializationContext` to use
 *
 * @return the deserialized `ObjectNode`
 *
 * @throws IOException if an I/O error occurs
 */
public ObjectNode deserialize(JsonParser p, DeserializationContext ctxt) throws IOException {
    if (p.getCurrentToken() == JsonToken.START_OBJECT) {
        p.nextToken();
        return deserializeObject(p, ctxt, ctxt.getNodeFactory());
    } else if (p.getCurrentToken() == JsonToken.FIELD_NAME) {
        return deserializeObject(p, ctxt, ctxt.getNodeFactory());
    } else if (p.getCurrentToken() == JsonToken.END_OBJECT) {
        p.nextToken();
        return null;
    }
    throw ctxt.mappingException(ObjectNode.class);
}

